echo 'from fastapi import FastAPI, HTTPException
from pydantic import BaseModel

app = FastAPI()

class LoginRequest(BaseModel):
    username: str
    password: str

@app.post("/api/login")
async def login(request: LoginRequest):
    # 简单验证逻辑
    if request.username == "admin" and request.password == "password":
        return {"message": "登录成功", "token": "fake-jwt-token"}
    else:
        raise HTTPException(status_code=401, detail="用户名或密码错误")
' > src/api/login.py

echo '<!DOCTYPE html>
<html>
<head>
    <title>用户登录</title>
</head>
<body>
    <h1>用户登录</h1>
    <form id="loginForm">
        <input type="text" id="username" placeholder="用户名"><br>
        <input type="password" id="password" placeholder="密码"><br>
        <button type="submit">登录</button>
    </form>
    <div id="message"></div>

    <script>
        document.getElementById("loginForm").addEventListener("submit", async (e) => {
            e.preventDefault();
            const username = document.getElementById("username").value;
            const password = document.getElementById("password").value;

            try {
                const response = await fetch("/api/login", {
                    method: "POST",
                    headers: { "Content-Type": "application/json" },
                    body: JSON.stringify({ username, password })
                });

                if (response.ok) {
                    const data = await response.json();
                    document.getElementById("message").innerHTML = 
                        `<p style="color: green;">\${data.message}</p>`;
                } else {
                    const error = await response.json();
                    document.getElementById("message").innerHTML = 
                        `<p style="color: red;">\${error.detail}</p>`;
                }
            } catch (error) {
                document.getElementById("message").innerHTML = 
                    `<p style="color: red;">网络错误: \${error.message}</p>`;
            }
        });
    </script>
</body>
</html>' > src/frontend/login.html
